(() => {
  const eventosAgendados = $json.data;
  const disponibilidadeSemanal = $('definir agenda').first().json;

  const timezone = disponibilidadeSemanal.timezone || "America/Sao_Paulo";
  const intervaloSemanas = 12;
  const intervaloMinutos =
    Number(disponibilidadeSemanal.timeBetweenMeetingsMinutes) || 30;

  const dayMap = {
    0: "DOM",
    1: "SEG",
    2: "TER",
    3: "QUA",
    4: "QUI",
    5: "SEX",
    6: "SAB"
  };

  function getDateWithTime(date, timeStr) {
    if (!timeStr) return null;
    const [hour, minute] = timeStr.split(":").map(Number);
    const d = new Date(date);
    d.setHours(hour, minute, 0, 0);
    return d;
  }

  function formatTime(date) {
    return date.toLocaleTimeString("pt-BR", {
      hour: "2-digit",
      minute: "2-digit",
      timeZone: timezone
    });
  }

  function formatDate(date) {
    return date.toLocaleDateString("en-CA", {
      timeZone: timezone
    }); // YYYY-MM-DD correto
  }

  function saoMesmoDia(a, b) {
    return (
      a.getFullYear() === b.getFullYear() &&
      a.getMonth() === b.getMonth() &&
      a.getDate() === b.getDate()
    );
  }

  function gerarHorariosDisponiveis() {
    const horariosDisponiveis = [];

    const agora = new Date(
      new Date().toLocaleString("en-US", { timeZone: timezone })
    );

    const hoje = new Date(agora);
    hoje.setHours(0, 0, 0, 0);

    const eventosValidos = Array.isArray(eventosAgendados)
      ? eventosAgendados.filter(e => e?.start?.dateTime && e?.end?.dateTime)
      : [];

    for (let i = 0; i < intervaloSemanas * 7; i++) {
      const dataAtual = new Date(hoje);
      dataAtual.setDate(hoje.getDate() + i);

      const diaSemana = dayMap[dataAtual.getDay()];
      const configDia = disponibilidadeSemanal.schedule.find(
        d => d.day === diaSemana
      );

      if (!configDia || !configDia.available) continue;

      let inicioJanela = getDateWithTime(dataAtual, configDia.hours.after);
      const fimJanela = getDateWithTime(dataAtual, configDia.hours.before);
      if (!inicioJanela || !fimJanela) continue;

      // Se for hoje, começa do horário atual
      if (i === 0 && inicioJanela < agora) {
        inicioJanela = new Date(agora);
        inicioJanela.setMinutes(
          Math.ceil(inicioJanela.getMinutes() / intervaloMinutos) *
            intervaloMinutos,
          0,
          0
        );
      }

      const eventosDoDia = eventosValidos.filter(evento => {
        const inicioEvento = new Date(evento.start.dateTime);
        const fimEvento = new Date(evento.end.dateTime);
        return (
          saoMesmoDia(inicioEvento, dataAtual) &&
          fimEvento > inicioJanela &&
          inicioEvento < fimJanela
        );
      });

      for (
        let slotInicio = new Date(inicioJanela);
        slotInicio < fimJanela;
        slotInicio = new Date(slotInicio.getTime() + intervaloMinutos * 60000)
      ) {
        const slotFim = new Date(
          slotInicio.getTime() + intervaloMinutos * 60000
        );
        if (slotFim > fimJanela) break;

        const conflita = eventosDoDia.some(evento => {
          const inicioEvento = new Date(evento.start.dateTime);
          const fimEvento = new Date(evento.end.dateTime);
          return slotInicio < fimEvento && slotFim > inicioEvento;
        });

        if (!conflita) {
          horariosDisponiveis.push({
            data: formatDate(slotInicio), // 🔥 SEM UTC
            start: formatTime(slotInicio),
            end: formatTime(slotFim)
          });
        }
      }
    }

    return horariosDisponiveis;
  }

  try {
    return JSON.stringify(gerarHorariosDisponiveis());
  } catch (err) {
    return JSON.stringify({
      error: err.message,
      stack: err.stack
    });
  }

})()

}}

